#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, L, S, R;
        scanf("%d %d %d %d", &N, &L, &S, &R);
        double dp[N + 1];
        dp[0] = 0;
        for (int i = 1; i <= N; i++) {
            dp[i] = 1 / (S / 100.0);
            if (i > 1) {
                dp[i] += (L / 100.0) * dp[i - 1];
            }
            if (i < N) {
                dp[i] += (R / 100.0) * dp[i + 1];
            }
        }
        printf("%.6f\n", dp[N]);
    }
    return 0;
}

